import{_ as t,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F07_存貨週轉效率同業對比_投資研究員.md"}'),e={name:"審計報告庫/財務審計/8064_東捷/20260429/F07_存貨週轉效率同業對比_投資研究員.md"};function o(n,a,s,h,c,_){return l(),i("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-投資研究員-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 投資研究員 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-投資研究員-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期是否處於擴張狀態？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：2024年DIO 275天、營運週期392天為同業末段；2025年雙收縮至DIO 161天、營運週期199天，惟主因Q4營收暴衝76%，可持續性存疑。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><p><strong>重點數據</strong>：2024 Q4→2025 Q4：DIO 275→161天(-41.6%)；DSO 117→38天(-67.6%)；營運週期392→199天(-49.4%)。同業2024 DIO：均豪75天/志聖119天/鈦昇311天/東捷275天。存貨13.7→10.9億(-20%)；AR 6.6→4.8億(-27%)。</p></li><li><p><strong>診斷見解</strong>：2024年東捷DIO為均豪3.6倍，屬「呆滯存貨」C級。2025年存貨減量2.8億、營收Q4跳增76%為改善主因，非純粹管理優化。DIO 161天仍為均豪2.1倍、志聖1.4倍。</p></li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="【供應鏈競爭階差對位】" tabindex="-1">【供應鏈競爭階差對位】 <a class="header-anchor" href="#【供應鏈競爭階差對位】" aria-label="Permalink to &quot;【供應鏈競爭階差對位】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：光電業平均DIO 61天 vs 東捷275天(C級)。設備業週期長有其特殊性但東捷為同業末段。2025 Q4 DIO 161天仍為均豪2.1倍、志聖1.4倍。</li><li><strong>深度見解</strong>：東捷自動化設備存貨含大量在製品（客製未出貨），均豪因半導體封裝設備佔比高自然優於東捷的FPD設備線。Q4 DIO改善為「存貨去化+營收跳升」同步效應。</li></ul><h3 id="【營運週期壓力測試】" tabindex="-1">【營運週期壓力測試】 <a class="header-anchor" href="#【營運週期壓力測試】" aria-label="Permalink to &quot;【營運週期壓力測試】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：營運週期437天(2023 Q4)→392天(2024 Q4)→199天(2025 Q4)，DSO縮減79天貢獻40%、DIO縮減114天貢獻60%。</li><li><strong>深度見解</strong>：Q4單季營收10.8億佔全年38%，導致季度DSO失真。還原全年DIO 193天+全年DSO 64天=257天，年度營運週期改善約98天（vs季度194天）。留意2026 Q1營收回落後DSO可能反彈至70-90天區間。</li></ul><h3 id="【通路博弈分析】" tabindex="-1">【通路博弈分析】 <a class="header-anchor" href="#【通路博弈分析】" aria-label="Permalink to &quot;【通路博弈分析】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：非傳統通路庫存問題。改善三大驅動：(1) Q4大型專案集中認列收入；(2) 存貨跌價損失1.06億→0.71億；(3) 營運現金流3.36億。</li><li><strong>深度見解</strong>：毛利率從26%升至28%，但更關鍵是備抵損失從8,772萬降至2,824萬(-68%)，顯示收款品質改善來自客戶履約能力回溫，非議價權提升。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一【季度噪音陷阱】</strong>：Q4營收10.8億佔全年38%，為營運週期收斂最核心的單一驅動。若2026 Q1營收回落至3-4億常態，DSO恐反彈至80天以上、營運週期重返300天。此改善之脆弱性令人警惕，不可線性外推。</li><li><strong>空頭風險二【存貨管理仍可疑】</strong>：2025年DIO 161天仍為光電業均值(61天)的2.6倍。2024年存貨跌價損失1.06億元反映庫存管理過去失靈，而管理層尚未提出可驗證的存貨壓縮路徑圖——若無系統性變革，高庫存週轉將成為結構性弱點。</li><li><strong>空頭風險三【合約負債攀升推高存貨負擔】</strong>：合約負債2.03億→2.42億(+19%)顯示訂單增長，但急單化將推高在製品存貨水位，使近期DIO改善動能趨緩，甚至逆轉。過度高估本次改善的可持續性是當前最大疑慮。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>HiStock 營運週轉天數</strong>：OK — 取得8064/5443/8027/2467各季DSO、DIO、營運週期完整時序。</li><li><strong>WantGoo 玩股網</strong>：OK — 8064 2024~2025 DIO/DSO逐季數據一致。</li><li><strong>年報/法說</strong>：OK — 114年度(2025)合併財報（資產負債表附註十、十一）驗證：存貨1,089,933千元、應收帳款476,606千元、應收票據24,548千元；113年度(2024)年報驗證存貨1,366,716千元、應收帳款655,059千元。</li><li><strong>關鍵核對碼</strong>： <ul><li>114年度存貨：1,089,933千（附註十一）</li><li>114年度AR淨額：476,606千（附註十）</li><li>113年度存貨：1,366,716千</li><li>113年度AR淨額：655,059千</li><li>同業DIO對比來源：HiStock「營運週轉天數」頁面截取</li></ul></li></ul>',19)])])}const g=t(e,[["render",o]]);export{u as __pageData,g as default};
